            {
                return NotFound("Invoice not found.");
            }

            // Tenant scoping: ensure the invoice belongs to the same tenant as the authenticated user
            if (!string.Equals(invoice.TenantId, currentTenantId, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning(
                    "Tenant mismatch: User {UserId} (Tenant {UserTenant}) attempted to access Invoice {InvoiceId} (Tenant {InvoiceTenant}).",
                    currentUserId, currentTenantId, invoiceId, invoice.TenantId);
