                return NotFound("Invoice not found.");
            }

            // Object-level authorization: non-admin users can only access their own invoices
            bool isAdmin = string.Equals(currentUserRole, "Admin", StringComparison.OrdinalIgnoreCase);

            if (!isAdmin && !string.Equals(invoice.UserId, currentUserId, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning(
                    "Unauthorized access: User {UserId} attempted to access Invoice {InvoiceId} owned by {OwnerId}.",
                    currentUserId, invoiceId, invoice.UserId);
